Hi everyone, here are the solutions to the contest problems.

712A — Memory and Crow

Note that a[i] + a[i + 1] = b[i]. Use the initial condition b[n] = a[n] and we can figure out the entire array b.

Time Complexity: O(n)
 Code
```
#include <bits/stdc++.h>

using namespace std;

int arr[100000];
int ans[100000];
int main()
{
    int n;
    cin >> n;
    for(int i=0; i < n; i++){
        cin >> arr[i];

    }

    for(int i = n-1; i >=0; i--){
        if(i==n-1) ans[i] = arr[i];
        else ans[i] = arr[i] + arr[i+1];
    }
    for(int i=0; i < n; i++){
        cout << ans[i] << " ";
    }
    cout << endl;
    return 0;
}


```

712B — Memory and Trident

First, if S has odd length, there is no possible string because letters must come in opposite pairs. Now, let's denote the ending coordinate after following S as (x, y). Since S has even length, |x| has the same parity as |y|. Suppose they are both even. Then clearly, we can make x = 0 in exactly  moves, and same for y. If instead they are both odd, then we can change exactly one x-character into a y-character. With the correct choices of these characters, now our string has |x| and |y| with even parity, thus reducing to the problem above. Therefore, the answer is (|x| + |y|) / 2.

Time Complexity: O(|S|)
 Code
```
#include <string>
#include <iostream>
#include <stdlib.h>
using namespace std;


int main()
{
    string str;
    cin >> str;
    if(str.length()%2==1){
        cout << -1 << endl;
        return 0;
    }

    int x=0,y=0;
    for(int i=0; i < str.length(); i++){
        if(str[i]=='U')y++;
        if(str[i]=='D')y--;
        if(str[i]=='L')x--;
        if(str[i]=='R')x++;
    }
    cout << (abs(x)+abs(y))/2 << endl;
}


```

712C — Memory and De-Evolution

Let's reverse the process: start with an equilateral triangle with side length y, and lets get to an equilateral triangle with side length x. In each step, we can act greedily while obeying the triangle inequality. This will give us our desired answer.

Time Complexity: O(log x)
 Code
```
#include <bits/stdc++.h>

using namespace std;

int main()
{
    int x,y;
    cin >> x >> y;

    int besta=y,bestb=y,bestc=y;

    int turns = 0;
    while(true){
        //check the current
        if(besta>=x && bestb>=x && bestc>=x){
            cout << turns << endl;
            break;
        }
        turns++;
        if(turns%3==1){
            //update a
            besta = bestb+bestc-1;
        }
        if(turns%3==2){
            //update b
            bestb = besta+bestc-1;
        }
        if(turns%3==0){
            //update c
            bestc = besta+bestb-1;
        }
    }
    return 0;
}

```

712D — Memory and Scores

One approach to this problem is by first implementing naive DP in O((kt)2). The state for this is (diff, turn), and transitions for (diff, turn) is the sum (diff - 2k, turn - 1) + 2(diff - 2k + 1, turn - 1) + 3(diff - 2k + 2, turn - 1) + ... + (2k + 1)(diff, turn - 1) + 2k(diff + 1, turn - 1) + ...   + diff( + 2k, turn - 1).

Now, if we use prefix sums of all differences in (turn-1), along with a sliding window technique across the differences, we can cut a factor of k, to achieve desired complexity O(kt2).

However, there is a much nicer solution in O(kt log kt) using generating functions(thanks to minimario). We can compute the coefficients of , and the coefficient to xi corresponds to the number of ways we can form the difference i. To compute these coefficients, we can use the binomial theorem.

Time Complexity: O(kt2)
 Code
```

#include <bits\stdc++.h>
using namespace std;

int MOD = 1000000007;
long long dp[2][1000000];
int lowest;

int h(int v){
    return v - lowest;
}
int main()
{
    int a,b,k,t;
    cin >> a >> b >> k >> t;
    int lowb = a-b;
    int highb = a-b;

    lowest = lowb - 2*k*(t);
    dp[0][h(lowb)] = 1l;
    //solve for ti = 0
    int curr = 1;
    for(int p = lowb-2*k; p<= lowb; p++){
        dp[1][h(p)] = curr;
        curr++;
    }
    curr--;
    for(int p = lowb+1; p<= lowb+2*k; p++){
        curr--;
        dp[1][h(p)] = curr;
    }
    lowb -=2*k;
    highb+=2*k;
    for(int ti = 1; ti <= t-1; ti++){
        int o = ti%2;
        vector<long long> pref;
        pref.push_back(dp[o][h(lowb)]);
        long long su = dp[o][h(lowb)];
        for(int p = lowb+1; p <= highb; p++){
            su = (su+dp[o][h(p)])%MOD;
            pref.push_back(su);
        }
        int pe = 2*k;
        int il = 0;
        int ir = 0;
        int l = lowb;
        int r = lowb;
        int np = lowb-2*k;
        long long sum = 0;
        //get the prefix first

        while(ir<=2*k){
            //evaluate current
            sum = (sum + pref[ir])%MOD;
            dp[!o][h(np)] = sum;
            //update for the next thing
            ir++;
            r++;
            np++;
        }
        pe = 0;
        ir--;
        r--;
        np--;
        while(pe<2*k){
            pe++;
            ir++;
            r++;
            np++;
            //evaluate
            sum = (sum + pref[ir])%MOD;
            sum = (sum - 2*pref[pe-1])%MOD;
            sum = (sum+MOD)%MOD;
            dp[!o][h(np)] = sum;
        }

        //slide into those dm's
        while(r<highb){
            //update
            pe++;
            r++;
            l++;
            ir++;
            il++;
            np++;

            long long sum1 = pref[pe-1] - ( (il==1) ? 0 : pref[(il-1)-1]);
            long long sum2 = pref[ir] - pref[pe-1];
            sum = (sum - sum1 + MOD)%MOD;
            sum = (sum + sum2)%MOD;
            dp[!o][h(np)] = sum;
        }
        //finally, suffix
        while(l<highb){
            l++;
            il++;
            pe++;
            np++;
            //subtract [l-1,pe-1]
            long long sum1 = pref[min(pe-1,ir)] - ((il==1) ? 0 : pref[il-1-1]);
            sum = (sum - sum1 + MOD)%MOD;
            if(pe>ir){

            }
            else{
                long long sum2 = pref[ir]-pref[pe-1];
                sum = (sum + sum2)%MOD;
            }
            dp[!o][h(np)] = sum;
        }

        lowb-=2*k;
        highb+=2*k;
    }
    long long ans = 0;
    int o = t%2;
    for(int p = 1; p <= highb; p++){
        ans = (ans+dp[o][h(p)])%MOD;
    }
    cout << ans << endl;
}


```

Time Complexity: O(kt log kt)
